const ethers = require('ethers');

// Set up the provider using your Ethereum node URL (e.g., Alchemy, Infura)
let provider = new ethers.providers.JsonRpcProvider("https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID");

// Set up the wallet using your private key
let wallet = new ethers.Wallet('0x...', provider); // replace '0x...' with your private key

// Connect to the token contract
const ERC20TokenContract = "0x..."; // replace '0x...' with the address of the token contract
const tokenContract = new ethers.Contract(ERC20TokenContract, ERC20TokenABI, wallet);

// Connect to the DEX contract
const DEXContract = "0x..."; // replace '0x...' with the address of the DEX contract
const dexContract = new ethers.Contract(DEXContract, DEXContractABI, wallet);

async function approveMaximum() {
  const name = await tokenContract.name();
  console.log("Token Name:", name);
  
  // Get the allowance for the connected address on the ERC20 contract
  const allowance = await tokenContract.allowance(wallet.address, dexContract.address);
  
  if (allowance.lt(ethers.constants.MaxUint256)) {
    console.log("Allowance not set to maximum for this DEX contract. Setting it now.");
    
    // Create the transaction and send it
    const tx = await tokenContract.approve(dexContract.address, ethers.constants.MaxUint256);
    await tx.wait();  // Wait for the transaction to be mined
  
    console.log("Allowance set successfully.");
  } else {
    console.log("Allowance already set to maximum for this DEX contract.");
  }
}